from flask import Flask, request, render_template_string
import importlib

app = Flask(__name__)

# Whitelist of allowed submodules to prevent arbitrary module loading (CWE-706)
ALLOWED_SUBMODULES = {'request', 'parse', 'error'}

@app.route('/')
def index():
    '''
    Get the module version from the request object
    and import the urllib submodule safely.
    '''
    version = request.args.get('version')

    # Validate input against a strict whitelist to prevent Remote Code Execution
    if version in ALLOWED_SUBMODULES:
        try:
            # Safe import because 'version' is validated against a whitelist
            importlib.import_module(f"urllib.{version}")

            # Use render_template_string to prevent Cross-Site Scripting (CWE-79)
            # Flask's Jinja2 engine automatically escapes variables passed to the template
            return render_template_string("Successfully imported urllib.{{ version }}", version=version)
        except ImportError:
            return "Module not found", 404
        except Exception:
            # Return a generic error message to avoid leaking system internals
            return "An internal error occurred", 500

    return "Invalid or missing version parameter", 400

import logging


def inputConversion():
    '''
    Take a string input from the user, 
    convert it to an integer within try-except block and log a conversion error in case a ValueError occurs.
    Return the converted user input.
    '''
    try:
        user_input = input("Please enter an integer: ")
        return int(user_input)
    except ValueError as e:
        logging.error("Conversion error: %s", e)
        return None

from Crypto.PublicKey import RSA

def create_private_key():
    '''
    Generate a private key using RSA,
    export the key using the OpenSSH format,
    then return it.
    '''
    key = RSA.generate(2048)
    return key.export_key(format='OpenSSH')

